export default {
  async fetch(request, env, ctx) {
    // Security: Only allow specific methods
    if (!['GET', 'POST', 'OPTIONS'].includes(request.method)) {
      return new Response('Method Not Allowed', { status: 405 });
    }

    // CORS handling
    if (request.method === 'OPTIONS') {
      return handleCORS(request, env);
    }

    const url = new URL(request.url);
    const response = await handleRequest(request, env, ctx, url);

    // Add security headers to all responses
    return addSecurityHeaders(response, env);
  }
};

// ==================== ROUTING ====================

async function handleRequest(request, env, ctx, url) {
  try {
    // Rate limiting
    const rateLimitResult = await checkRateLimit(request, env);
    if (!rateLimitResult.allowed) {
      return jsonResponse({ error: 'Rate limit exceeded. Try again later.' }, 429, {
        'Retry-After': String(rateLimitResult.retryAfter)
      });
    }

    // Route matching
    const path = url.pathname;

    // Health check (no auth required)
    if (path === '/health' && request.method === 'GET') {
      return jsonResponse({ status: 'ok', timestamp: new Date().toISOString() }, 200);
    }

    // Stripe webhook (uses Stripe signature verification, not API token)
    if (path === '/webhooks/stripe' && request.method === 'POST') {
      return handleStripeWebhook(request, env);
    }

    // All other routes require authentication
    const authResult = await authenticateRequest(request, env);
    if (!authResult.authenticated) {
      return jsonResponse({ error: authResult.error }, 401);
    }

    // Authenticated routes
    switch (true) {
      case path === '/api/email/send' && request.method === 'POST':
        return handleSendEmail(request, env);

      case path === '/api/payments/create-intent' && request.method === 'POST':
        return handleCreatePaymentIntent(request, env);

      case path === '/api/payments/customers' && request.method === 'POST':
        return handleCreateCustomer(request, env);

      case path === '/api/payments/customers' && request.method === 'GET':
        return handleGetCustomer(request, env, url);

      case path === '/api/payments/subscriptions' && request.method === 'POST':
        return handleCreateSubscription(request, env);

      case path === '/api/payments/refund' && request.method === 'POST':
        return handleRefund(request, env);

      default:
        return jsonResponse({ error: 'Not Found' }, 404);
    }
  } catch (error) {
    console.error('Unhandled error:', error.message, error.stack);
    return jsonResponse({
      error: 'Internal Server Error',
      requestId: crypto.randomUUID()
    }, 500);
  }
}

// ==================== AUTHENTICATION ====================

async function authenticateRequest(request, env) {
  const authHeader = request.headers.get('Authorization');

  if (!authHeader) {
    return { authenticated: false, error: 'Missing Authorization header' };
  }

  // Support Bearer token authentication
  const match = authHeader.match(/^Bearer\s+(.+)$/i);
  if (!match) {
    return { authenticated: false, error: 'Invalid Authorization format. Use: Bearer <token>' };
  }

  const providedToken = match[1];

  // Constant-time comparison to prevent timing attacks
  const expectedToken = env.API_AUTH_TOKEN;
  if (!expectedToken) {
    console.error('API_AUTH_TOKEN secret not configured');
    return { authenticated: false, error: 'Server authentication misconfigured' };
  }

  const isValid = await constantTimeCompare(providedToken, expectedToken);
  if (!isValid) {
    return { authenticated: false, error: 'Invalid authentication token' };
  }

  return { authenticated: true };
}

async function constantTimeCompare(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') {
    return false;
  }

  const encoder = new TextEncoder();
  const aBytes = encoder.encode(a);
  const bBytes = encoder.encode(b);

  if (aBytes.length !== bBytes.length) {
    // Hash both to still do constant-time comparison
    const aHash = await crypto.subtle.digest('SHA-256', aBytes);
    const bHash = await crypto.subtle.digest('SHA-256', bBytes);
    const aArr = new Uint8Array(aHash);
    const bArr = new Uint8Array(bHash);
    let result = 1; // Will be non-zero since lengths differ
    for (let i = 0; i < aArr.length; i++) {
      result |= aArr[i] ^ bArr[i];
    }
    return false;
  }

  let result = 0;
  for (let i = 0; i < aBytes.length; i++) {
    result |= aBytes[i] ^ bBytes[i];
  }
  return result === 0;
}

// ==================== RATE LIMITING ====================

async function checkRateLimit(request, env) {
  if (!env.RATE_LIMIT_KV) {
    // If KV not configured, allow request but log warning
    console.warn('RATE_LIMIT_KV not configured, skipping rate limiting');
    return { allowed: true };
  }

  const clientIP = request.headers.get('CF-Connecting-IP') || 'unknown';
  const key = `ratelimit:${clientIP}`;
  const windowSeconds = 60;
  const maxRequests = 60;

  try {
    const current = await env.RATE_LIMIT_KV.get(key, 'json');
    const now = Math.floor(Date.now() / 1000);

    if (!current || current.windowStart + windowSeconds < now) {
      // New window
      await env.RATE_LIMIT_KV.put(key, JSON.stringify({
        count: 1,
        windowStart: now
      }), { expirationTtl: windowSeconds * 2 });
      return { allowed: true };
    }

    if (current.count >= maxRequests) {
      const retryAfter = current.windowStart + windowSeconds - now;
      return { allowed: false, retryAfter };
    }

    // Increment
    await env.RATE_LIMIT_KV.put(key, JSON.stringify({
      count: current.count + 1,
      windowStart: current.windowStart
    }), { expirationTtl: windowSeconds * 2 });

    return { allowed: true };
  } catch (error) {
    console.error('Rate limit check failed:', error.message);
    // Fail open - allow request if rate limiting fails
    return { allowed: true };
  }
}

// ==================== SENDGRID EMAIL HANDLERS ====================

async function handleSendEmail(request, env) {
  const body = await parseAndValidateJSON(request);
  if (body.error) {
    return jsonResponse({ error: body.error }, 400);
  }

  const { to, subject, text, html, from, templateId, dynamicTemplateData } = body.data;

  // Input validation
  const validationErrors = [];

  if (!to || !isValidEmail(to)) {
    validationErrors.push('Valid "to" email address is required');
  }
  if (!subject && !templateId) {
    validationErrors.push('"subject" is required when not using a template');
  }
  if (!text && !html && !templateId) {
    validationErrors.push('"text" or "html" content is required when not using a template');
  }
  if (subject && subject.length > 998) {
    validationErrors.push('"subject" must be less than 998 characters');
  }
  if (templateId && typeof templateId !== 'string') {
    validationErrors.push('"templateId" must be a string');
  }

  if (validationErrors.length > 0) {
    return jsonResponse({ error: 'Validation failed', details: validationErrors }, 400);
  }

  // Sanitize inputs
  const sanitizedSubject = sanitizeString(subject);
  const senderEmail = from && isValidEmail(from) ? from : 'noreply@yourdomain.com';

  // Build SendGrid payload
  const sendGridPayload = {
    personalizations: [{
      to: [{ email: sanitizeString(to) }]
    }],
    from: { email: senderEmail },
  };

  if (templateId) {
    sendGridPayload.template_id = sanitizeString(templateId);
    if (dynamicTemplateData && typeof dynamicTemplateData === 'object') {
      sendGridPayload.personalizations[0].dynamic_template_data = dynamicTemplateData;
    }
  } else {
    sendGridPayload.subject = sanitizedSubject;
    sendGridPayload.content = [];
    if (text) {
      sendGridPayload.content.push({ type: 'text/plain', value: text });
    }
    if (html) {
      sendGridPayload.content.push({ type: 'text/html', value: html });
    }
  }

  try {
    const sgResponse = await fetchWithTimeout('https://api.sendgrid.com/v3/mail/send', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${env.SENDGRID_API_KEY}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(sendGridPayload),
    }, 10000);

    if (sgResponse.ok) {
      return jsonResponse({
        success: true,
        message: 'Email queued for delivery',
        messageId: sgResponse.headers.get('X-Message-Id') || null
      }, 202);
    }

    // Handle SendGrid errors
    const errorBody = await sgResponse.text();
    let errorDetail;
    try {
      errorDetail = JSON.parse(errorBody);
    } catch {
      errorDetail = { raw: errorBody };
    }

    console.error('SendGrid API error:', sgResponse.status, JSON.stringify(errorDetail));

    if (sgResponse.status === 401) {
      return jsonResponse({ error: 'Email service authentication failed' }, 502);
    }
    if (sgResponse.status === 429) {
      return jsonResponse({ error: 'Email service rate limit reached' }, 503);
    }

    return jsonResponse({
      error: 'Email service error',
      statusCode: sgResponse.status,
      details: errorDetail?.errors?.map(e => e.message) || 'Unknown error'
    }, 502);

  } catch (error) {
    if (error.name === 'TimeoutError') {
      return jsonResponse({ error: 'Email service timeout' }, 504);
    }
    console.error('SendGrid request failed:', error.message);
    return jsonResponse({ error: 'Failed to connect to email service' }, 502);
  }
}

// ==================== STRIPE PAYMENT HANDLERS ====================

async function handleCreatePaymentIntent(request, env) {
  const body = await parseAndValidateJSON(request);
  if (body.error) {
    return jsonResponse({ error: body.error }, 400);
  }

  const { amount, currency, customerId, metadata, description, receiptEmail } = body.data;

  // Validation
  const validationErrors = [];

  if (!amount || typeof amount !== 'number' || amount < 50) {
    validationErrors.push('"amount" must be a number >= 50 (in cents)');
  }
  if (amount > 99999999) {
    validationErrors.push('"amount" exceeds maximum allowed value');
  }
  if (!currency || typeof currency !== 'string' || currency.length !== 3) {
    validationErrors.push('"currency" must be a 3-letter ISO currency code');
  }
  if (receiptEmail && !isValidEmail(receiptEmail)) {
    validationErrors.push('"receiptEmail" must be a valid email');
  }

  if (validationErrors.length > 0) {
    return jsonResponse({ error: 'Validation failed', details: validationErrors }, 400);
  }

  const params = new URLSearchParams();
  params.append('amount', Math.round(amount).toString());
  params.append('currency', currency.toLowerCase());
  params.append('automatic_payment_methods[enabled]', 'true');

  if (customerId) {
    params.append('customer', sanitizeString(customerId));
  }
  if (description) {
    params.append('description', sanitizeString(description).substring(0, 1000));
  }
  if (receiptEmail) {
    params.append('receipt_email', sanitizeString(receiptEmail));
  }
  if (metadata && typeof metadata === 'object') {
    for (const [key, value] of Object.entries(metadata)) {
      if (typeof value === 'string' || typeof value === 'number') {
        params.append(`metadata[${sanitizeString(key)}]`, String(value).substring(0, 500));
      }
    }
  }

  return stripeRequest('/v1/payment_intents', 'POST', params, env, (data) => ({
    success: true,
    paymentIntent: {
      id: data.id,
      clientSecret: data.client_secret,
      amount: data.amount,
      currency: data.currency,
      status: data.status,
    }
  }));
}

