  if (body.error) {
    return jsonResponse({ error: body.error }, 400);
  }

  const { customerId, priceId, trialPeriodDays, metadata } = body.data;

  const validationErrors = [];
  if (!customerId || !customerId.startsWith('cus_')) {
    validationErrors.push('Valid "customerId" is required');
  }
  if (!priceId || !priceId.startsWith('price_')) {
    validationErrors.push('Valid "priceId" is required');
  }
  if (trialPeriodDays !== undefined && (typeof trialPeriodDays !== 'number' || trialPeriodDays < 0 || trialPeriodDays > 730)) {
    validationErrors.push('"trialPeriodDays" must be a number between 0 and 730');
  }

  if (validationErrors.length > 0) {
    return jsonResponse({ error: 'Validation failed', details: validationErrors }, 400);
  }

  const params = new URLSearchParams();
  params.append('customer', sanitizeString(customerId));
  params.append('items[0][price]', sanitizeString(priceId));
  params.append('payment_behavior', 'default_incomplete');
  params.append('expand[]', 'latest_invoice.payment_intent');

  if (trialPeriodDays) {
    params.append('trial_period_days', Math.round(trialPeriodDays).toString());
  }
  if (metadata && typeof metadata === 'object') {
    for (const [key, value] of Object.entries(metadata)) {
      if (typeof value === 'string' || typeof value === 'number') {
        params.append(`metadata[${sanitizeString(key)}]`, String(value).substring(0, 500));
      }
    }
  }

  return stripeRequest('/v1/subscriptions', 'POST', params, env, (data) => ({
    success: true,
    subscription: {
      id: data.id,
      status: data.status,
      currentPeriodEnd: data.current_period_end,
      clientSecret: data.latest_invoice?.payment_intent?.client_secret || null,
    }
  }));
