async function handleRefund(request, env) {
  const body = await parseAndValidateJSON(request);
  if (body.error) {
    return jsonResponse({ error: body.error }, 400);
  }

  const { paymentIntentId, amount, reason } = body.data;

  const validationErrors = [];
  if (!paymentIntentId || !paymentIntentId.startsWith('pi_')) {
    validationErrors.push('Valid "paymentIntentId" is required');
  }
  if (amount !== undefined && (typeof amount !== 'number' || amount < 1)) {
    validationErrors.push('"amount" must be a positive number (in cents)');
  }
  if (reason && !['duplicate', 'fraudulent', 'requested_by_customer'].includes(reason)) {
    validationErrors.push('"reason" must be one of: duplicate, fraudulent, requested_by_customer');
  }

  if (validationErrors.length > 0) {
    return jsonResponse({ error: 'Validation failed', details: validationErrors }, 400);
  }

  const params = new URLSearchParams();
  params.append('payment_intent', sanitizeString(paymentIntentId));
  if (amount) params.append('amount', Math.round(amount).toString());
  if (reason) params.append('reason', reason);

  return stripeRequest('/v1/refunds', 'POST', params, env, (data) => ({
    success: true,
    refund: {
      id: data.id,
      amount: data.amount,
      currency: data.currency,
      status: data.status,
    }
  }));
}

// ==================== STRIPE WEBHOOK HANDLER ====================

async function handleStripeWebhook(request, env) {
  const STRIPE_WEBHOOK_SECRET = env.STRIPE_WEBHOOK_SECRET;
  if (!STRIPE_WEBHOOK_SECRET) {
    console.error('STRIPE_WEBHOOK_SECRET not configured');
    return jsonResponse({ error: 'Webhook not configured' }, 500);
  }

  const signature = request.headers.get('stripe-signature');
  if (!signature) {
    return jsonResponse({ error: 'Missing stripe-signature header' }, 400);
  }

  const rawBody = await request.text();

  // Verify webhook signature
  const isValid = await verifyStripeSignature(rawBody, signature, STRIPE_WEBHOOK_SECRET);
  if (!isValid) {
    console.error('Invalid Stripe webhook signature');
    return jsonResponse({ error: 'Invalid signature' }, 401);
  }

  let event;
  try {
    event = JSON.parse(rawBody);
  } catch {
    return jsonResponse({ error: 'Invalid JSON payload' }, 400);
  }

  // Process webhook events
  try {
    switch (event.type) {
      case 'payment_intent.succeeded':
        console.log('Payment succeeded:', event.data.object.id);
        // Add your business logic here
        break;

      case 'payment_intent.payment_failed':
        console.log('Payment failed:', event.data.object.id);
        break;

      case 'customer.subscription.created':
        console.log('Subscription created:', event.data.object.id);
        break;

      case 'customer.subscription.updated':
        console.log('Subscription updated:', event.data.object.id);
        break;

      case 'customer.subscription.deleted':
        console.log('Subscription cancelled:', event.data.object.id);
        break;

      case 'invoice.payment_succeeded':
        console.log('Invoice paid:', event.data.object.id);
        break;

      case 'invoice.payment_failed':
        console.log('Invoice payment failed:', event.data.object.id);
        // Could trigger a SendGrid email notification here
        break;

      case 'charge.refunded':
        console.log('Charge refunded:', event.data.object.id);
        break;

      default:
        console.log('Unhandled webhook event type:', event.type);
    }

    return jsonResponse({ received: true }, 200);
  } catch (error) {
    console.error('Webhook processing error:', error.message);
    // Return 200 to prevent Stripe from retrying
    return jsonResponse({ received: true, processingError: true }, 200);
  }
}

async function verifyStripeSignature(payload, signatureHeader, secret) {
  try {
    const parts = signatureHeader.split(',').reduce((acc, part) => {
      const [key, value] = part.split('=');
      acc[key.trim()] = value;
      return acc;
    }, {});

    const timestamp = parts['t'];
    const signature = parts['v1'];

    if (!timestamp || !signature) {
      return false;
    }

    // Check timestamp tolerance (5 minutes)
    const now = Math.floor(Date.now() / 1000);
    if (Math.abs(now - parseInt(timestamp)) > 300) {
      console.error('Stripe webhook timestamp too old');
      return false;
    }

    const signedPayload = `${timestamp}.${payload}`;
    const encoder = new TextEncoder();

    const key = await crypto.subtle.importKey(
      'raw',
      encoder.encode(secret),
      { name: 'HMAC', hash: 'SHA-256' },
      false,
      ['sign']
    );

    const signatureBuffer = await crypto.subtle.sign(
      'HMAC',
      key,
      encoder.encode(signedPayload)
    );

    const expectedSignature = Array.from(new Uint8Array(signatureBuffer))
      .map(b => b.toString(16).padStart(2, '0'))
      .join('');

    // Constant-time comparison
    if (expectedSignature.length !== signature.length) {
      return false;
    }

    let result = 0;
    for (let i = 0; i < expectedSignature.length; i++) {
      result |= expectedSignature.charCodeAt(i) ^ signature.charCodeAt(i);
    }

    return result === 0;
  } catch (error) {
    console.error('Signature verification error:', error.message);
    return false;
  }
}

// ==================== STRIPE API HELPER ====================

async function stripeRequest(path, method, params, env, transformResponse) {
  if (!env.STRIPE_SECRET_KEY) {
    console.error('STRIPE_SECRET_KEY not configured');
    return jsonResponse({ error: 'Payment service not configured' }, 500);
  }

  try {
    const options = {
      method,
      headers: {
        'Authorization': `Bearer ${env.STRIPE_SECRET_KEY}`,
        'Stripe-Version': '2023-10-16',
        'Content-Type': 'application/x-www-form-urlencoded',
      },
    };

    if (params && method === 'POST') {
      options.body = params.toString();
    }

    const url = `https://api.stripe.com${path}`;
    const response = await fetchWithTimeout(url, options, 15000);

    const responseData = await response.json();

    if (response.ok) {
      return jsonResponse(transformResponse(responseData), response.status === 200 ? 200 : 201);
    }

    // Handle Stripe errors
    console.error('Stripe API error:', response.status, JSON.stringify(responseData));

    const stripeError = responseData.error || {};

    if (response.status === 401) {
      return jsonResponse({ error: 'Payment service authentication failed' }, 502);
    }

    if (response.status === 429) {
      return jsonResponse({ error: 'Payment service rate limit reached' }, 503);
    }

    // Map Stripe error types to user-friendly messages
    const errorMessages = {
      'card_error': stripeError.message || 'Card was declined',
      'invalid_request_error': 'Invalid payment request',
      'authentication_error': 'Payment service authentication failed',
      'rate_limit_error': 'Too many requests to payment service',
      'api_connection_error': 'Could not connect to payment service',
      'api_error': 'Payment service error',
    };

    return jsonResponse({
      error: errorMessages[stripeError.type] || 'Payment processing error',
      code: stripeError.code || undefined,
      declineCode: stripeError.decline_code || undefined,
    }, stripeError.type === 'card_error' ? 400 : 502);

  } catch (error) {
    if (error.name === 'TimeoutError') {
      return jsonResponse({ error: 'Payment service timeout' }, 504);
    }
    console.error('Stripe request failed:', error.message);
    return jsonResponse({ error: 'Failed to connect to payment service' }, 502);
  }
}

// ==================== UTILITY FUNCTIONS ====================

async function fetchWithTimeout(url, options, timeoutMs) {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), timeoutMs);

  try {
    const response = await fetch(url, {
      ...options,
      signal: controller.signal,
    });
    return response;
  } catch (error) {
    if (error.name === 'AbortError') {
      const timeoutError = new Error('Request timeout');
      timeoutError.name = 'TimeoutError';
      throw timeoutError;
    }
    throw error;
  } finally {
    clearTimeout(timeoutId);
  }
}

async function parseAndValidateJSON(request) {
  const contentType = request.headers.get('Content-Type');
  if (!contentType || !contentType.includes('application/json')) {
    return { error: 'Content-Type must be application/json' };
  }

  // Limit body size (1MB)
  const contentLength = request.headers.get('Content-Length');
  if (contentLength && parseInt(contentLength) > 1048576) {
    return { error: 'Request body too large (max 1MB)' };
  }

  try {
    const text = await request.text();
    if (text.length > 1048576) {
      return { error: 'Request body too large (max 1MB)' };
    }
    const data = JSON.parse(text);
    if (typeof data !== 'object' || data === null || Array.isArray(data)) {
      return { error: 'Request body must be a JSON object' };
    }
    return { data };
  } catch {
    return { error: 'Invalid JSON in request body' };
  }
}

function isValidEmail(email) {
  if (typeof email !== 'string') return false;
  if (email.length > 254) return false;
  const emailRegex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/;
  return emailRegex.test(email);
}

function sanitizeString(input) {
  if (typeof input !== 'string') return '';
  // Remove null bytes and control characters (except common whitespace)
  return input.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '').trim();
}

function jsonResponse(data, status = 200, extraHeaders = {}) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json',
      ...extraHeaders,
    },
  });
}

function handleCORS(request, env) {
  const origin = request.headers.get('Origin');
  const allowedOrigins = (env.ALLOWED_ORIGINS || '').split(',').map(o => o.trim());

  const headers = {
    'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, Authorization',
    'Access-Control-Max-Age': '86400',
  };

  if (allowedOrigins.includes(origin)) {
    headers['Access-Control-Allow-Origin'] = origin;
  }

  return new Response(null, { status: 204, headers });
}

function addSecurityHeaders(response, env) {
  const newResponse = new Response(response.body, response);

  // Security headers
  newResponse.headers.set('X-Content-Type-Options', 'nosniff');
  newResponse.headers.set('X-Frame-Options', 'DENY');
  newResponse.headers.set('X-XSS-Protection', '0');
  newResponse.headers.set('Referrer-Policy', 'strict-origin-when-cross-origin');
  newResponse.headers.set('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  newResponse.headers.set('Content-Security-Policy', "default-src 'none'; frame-ancestors 'none'");
  newResponse.headers.set('Permissions-Policy', 'camera=(), microphone=(), geolocation=()');

  // CORS - set origin if allowed
  const origin = newResponse.headers.get('Origin');
  if (!newResponse.headers.has('Access-Control-Allow-Origin')) {
    const allowedOrigins = (env.ALLOWED_ORIGINS || '').split(',').map(o => o.trim());
    if (origin && allowedOrigins.includes(origin)) {
      newResponse.headers.set('Access-Control-Allow-Origin', origin);
      newResponse.headers.set('Vary', 'Origin');
    }
  }

  // Remove server identification
  newResponse.headers.delete('Server');

  return newResponse;
}